// Safely extract meetingId from all possible payload structures
const raw = $input.first().json;

const meetingId =
  raw.meetingId ||
  raw.body?.meetingId ||
  raw.data?.meetingId ||
  raw.payload?.meetingId ||
  '';

const eventType =
  raw.eventType ||
  raw.body?.eventType ||
  'Transcription completed';

return [{
  json: {
    isValid: !!meetingId,
    meetingId: meetingId.trim(),
    eventType
  }
}];

