const response = $input.first().json;
const config = $('5. Set — Config Values').item.json;

const transcript = response?.data?.transcript;

if (!transcript || !transcript.id) {
  return [{
    json: {
      hasData: false,
      meetingId: config.meetingId,
      error: 'Transcript not found or not ready in Fireflies'
    }
  }];
}

// Collect action items from Fireflies summary
const rawActionItems = transcript.summary?.action_items || [];

// ALSO collect sentences flagged as tasks by Fireflies NLP
const sentences = transcript.sentences || [];
const taskSentences = sentences
  .filter(s => s.ai_filters?.task && (s.text || '').length > 10)
  .map(s => (s.speaker_name ? s.speaker_name + ': ' + s.text : s.text))
  .slice(0, 10);

// Combine both sources
const allActionSources = [
  ...rawActionItems,
  ...taskSentences
];

// Deduplicate and clean
const uniqueItems = [...new Set(allActionSources)]
  .filter(item => item && item.trim().length > 5)
  .slice(0, 15);

if (uniqueItems.length === 0) {
  return [{
    json: {
      hasData: false,
      meetingId: transcript.id,
      error: 'No action items found in this meeting'
    }
  }];
}

const meetingDate = transcript.date
  ? new Date(transcript.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
  : new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

const durationMin = Math.round((transcript.duration || 0) / 60);
const participants = (transcript.participants || []).join(', ') || 'Not listed';
const overview = (transcript.summary?.overview || '').substring(0, 500);
const keywords = (transcript.summary?.keywords || []).slice(0, 8).join(', ');

return [{
  json: {
    hasData: true,
    meetingId: transcript.id,
    meetingTitle: transcript.title || 'Untitled Meeting',
    meetingDate,
    durationMin,
    participants,
    overview,
    keywords,
    actionItemsRaw: uniqueItems.join('\n'),
    actionItemCount: uniqueItems.length,
    clickupApiToken: config.clickupApiToken,
    clickupListId: config.clickupListId,
    telegramChatId: config.telegramChatId,
    hostName: config.hostName,
    companyName: config.companyName
  }
}];

parameters.inputSchema:
{
  "type": "array",
  "items": {
    "type": "object",
    "properties": {
      "taskName": {
        "type": "string",
        "description": "Clean actionable task title starting with a verb. Max 60 chars."
      },
      "owner": {
        "type": "string",
        "description": "Person responsible for this task. Use Unassigned if not mentioned."
      },
      "deadline": {
        "type": "string",
        "description": "Deadline date in YYYY-MM-DD format"
      },
      "priority": {
        "type": "number",
        "description": "Priority: 1=Urgent 2=High 3=Normal 4=Low"
      }
    },
    "required": ["taskName", "owner", "deadline", "priority"]
  }
}

