// Convert parsed tasks array into individual items for ClickUp loop
const aiOutput = $input.first().json.output;
const meetingData = $('7. Code — Process Action Items').item.json;

if (!aiOutput || !Array.isArray(aiOutput) || aiOutput.length === 0) {
  return [{
    json: {
      hasTasksToCreate: false,
      error: 'No structured tasks returned from AI',
      meetingTitle: meetingData.meetingTitle,
      telegramChatId: meetingData.telegramChatId,
      hostName: meetingData.hostName
    }
  }];
}

// Return ONE item per task
return aiOutput.map((task, index) => {
  const deadlineMs = task.deadline
    ? new Date(task.deadline).getTime()
    : Date.now() + (2 * 24 * 60 * 60 * 1000);

  const priorityNum = parseInt(task.priority) || 3;
  const validPriority = [1, 2, 3, 4].includes(priorityNum) ? priorityNum : 3;

  return {
    json: {
      hasTasksToCreate: true,
      taskName: (task.taskName || 'Untitled Task').substring(0, 100),
      owner: task.owner || 'Unassigned',
      deadline: task.deadline || 'Not set',
      deadlineMs,
      priority: validPriority,
      taskIndex: index + 1,
      totalTasks: aiOutput.length,
      isLastTask: index === aiOutput.length - 1,
      meetingTitle: meetingData.meetingTitle,
      meetingDate: meetingData.meetingDate,
      meetingId: meetingData.meetingId,
      clickupApiToken: meetingData.clickupApiToken,
      clickupListId: meetingData.clickupListId,
      telegramChatId: meetingData.telegramChatId,
      hostName: meetingData.hostName,
      companyName: meetingData.companyName
    }
  };
});

// Build Telegram summary message after all tasks created
const lastTaskData = $('13. Code — Split Tasks for Loop').item.json;
const totalTasks = lastTaskData.totalTasks;
const meetingTitle = lastTaskData.meetingTitle;
const meetingDate = lastTaskData.meetingDate;
const hostName = lastTaskData.hostName;
const companyName = lastTaskData.companyName;

const message =
  'Meeting Action Items Created in ClickUp\n' +
  '\n' +
  'Meeting: ' + meetingTitle + '\n' +
  'Date: ' + meetingDate + '\n' +
  'Tasks Created: ' + totalTasks + ' tasks\n' +
  '\n' +
  'All tasks have been added to your ClickUp list automatically.\n' +
  'Check ClickUp to review, assign, and adjust deadlines.\n' +
  '\n' +
  'Powered by ' + companyName + ' + Fireflies.ai + GPT-4o-mini';

return [{
  json: {
    telegramMessage: message,
    telegramChatId: lastTaskData.telegramChatId
  }
}];
